// --- Worker Actor that processes validated messages ---
class WorkerActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case TextMessage(sender, content) =>
      log.info(s"Received text from '$sender': $content")

    case PingMessage(timestamp) =>
      log.info(s"Received ping at $timestamp, sending pong")
      sender() ! PongMessage(System.currentTimeMillis())

    case PongMessage(timestamp) =>
      log.info(s"Received pong with timestamp $timestamp")

    case StatusRequest(requestId) =>
      log.info(s"Status request: $requestId")
      sender() ! StatusResponse(requestId, "OK")

    case StatusResponse(requestId, status) =>
      log.info(s"Status response for $requestId: $status")

    case unknown =>
      log.warning(s"Received unknown message type: ${unknown.getClass.getName} - dropping")
  }
}

// --- TCP Connection Handler with safe deserialization ---
class ConnectionHandler(workerActor: akka.actor.ActorRef) extends Actor with ActorLogging {
  import Tcp._

  private val MaxBufferSize = 65536

  override def receive: Receive = {
    case Received(data) =>
      val bytes = data.toArray
      if (bytes.length > MaxBufferSize) {
        log.warning(s"Received oversized message (${bytes.length} bytes) - dropping")
        sender() ! Close
      } else {
        SafeMessageProtocol.deserialize(bytes) match {
          case Right(msg) =>
            log.info(s"Successfully deserialized safe message: ${msg.getClass.getSimpleName}")
            workerActor ! msg
          case Left(error) =>
            log.warning(s"Rejected untrusted message: $error")
            // Do NOT process the message - it failed validation
        }
      }

    case PeerClosed =>
      log.info("Peer closed connection")
      context.stop(self)

    case ErrorClosed(cause) =>
      log.warning(s"Connection error: $cause")
      context.stop(self)
  }
}

// --- TCP Server Actor ---
class TcpServer(host: String, port: Int, workerActor: akka.actor.ActorRef) extends Actor with ActorLogging {
  import Tcp._
  import context.system

  IO(Tcp) ! Bind(self, new InetSocketAddress(host, port))

  override def receive: Receive = {
    case Bound(localAddress) =>
      log.info(s"Server bound to $localAddress")

    case CommandFailed(_: Bind) =>
      log.error(s"Failed to bind to $host:$port")
      context.stop(self)

    case Connected(remote, local) =>
      log.info(s"New connection from $remote")
      val handler = context.actorOf(Props(new ConnectionHandler(workerActor)))
      sender() ! Register(handler)
  }
}

